mapper.select:
SELECT da.arrangement_id, da.defense_type, da.topic_category, da.major_id, mi.major_name, da.defense_time, da.defense_location, da.panel_teachers, da.deadline, da.cohort, da.enterprise_id, e.enterprise_name, da.creator_id, u.real_name AS creator_name, da.status, da.remark, da.create_time, da.update_time FROM defense_arrangement da LEFT JOIN enterprise_info e ON da.enterprise_id COLLATE utf8mb4_unicode_ci = e.enterprise_id COLLATE utf8mb4_unicode_ci LEFT JOIN user_info u ON da.creator_id COLLATE utf8mb4_unicode_ci = u.user_id COLLATE utf8mb4_unicode_ci LEFT JOIN major_info mi ON da.major_id COLLATE utf8mb4_unicode_ci = mi.major_id COLLATE utf8mb4_unicode_ci AND mi.deleted = 0 WHERE da.is_deleted = 0
AND da.enterprise_id = #{enterpriseId}
AND da.defense_type = #{defenseType}
AND da.topic_category = #{topicCategory}
AND da.major_id = #{majorId}
AND da.cohort = #{cohort}
AND da.status = #{status}
ORDER BY da.defense_time DESC
